    "selfCheckQuestions": [
      "Who discovered the cell and what material did he use?",
      "What is the main difference between a prokaryotic and eukaryotic cell?"
    ],
    "didYouKnow": [
      "The word 'Cell' comes from the Latin word 'Cella', meaning a small room or apartment."
    ],
